func statusClass(status string) string {
	switch status {
	case "ACTIVE":
		return "badge badge-ok"
	case "PAUSED", "DRAINING":
		return "badge badge-warn"
	default:
		return "badge"
	}
}

func canCancel(status string) bool {
	return status == "ACTIVE" || status == "PAUSED"
}

